import EventKit
import SwiftUI
@MainActor final class CalendarSyncManager: ObservableObject { static let shared = CalendarSyncManager(); private let eventStore = EKEventStore()
    func requestCalendarAccess() { if #available(iOS 17.0, *) { eventStore.requestFullAccessToEvents { granted, error in if let error { print("[CalendarSyncManager] 日历权限请求失败: \(error.localizedDescription)") } else if granted { print("[CalendarSyncManager] 日历写入权限已授权") } else { print("[CalendarSyncManager] 用户拒绝了日历权限") } } } else { eventStore.requestAccess(to: .event) { granted, error in if let error { print("[CalendarSyncManager] 日历权限请求失败: \(error.localizedDescription)") } else if granted { print("[CalendarSyncManager] 日历写入权限已授权") } else { print("[CalendarSyncManager] 用户拒绝了日历权限") } } } }
    func syncToSystemCalendar(event: Event) { guard let eventDate = event.date else { print("[CalendarSyncManager] 事件无日期，跳过同步: \(event.title)"); return }; if let existingID = event.systemCalendarEventIdentifier { removeEKEvent(by: existingID) }; let ekEvent = EKEvent(eventStore: eventStore); ekEvent.title = event.title; ekEvent.startDate = eventDate; if let endDate = event.endDate { ekEvent.endDate = endDate } else if event.isAllDay { ekEvent.endDate = eventDate } else { ekEvent.endDate = eventDate.addingTimeInterval(3600) }; ekEvent.isAllDay = event.isAllDay; if let location = event.location, !location.isEmpty { ekEvent.location = location }; var notesParts: [String] = ["[通过「连接」App 创建]", "类型：\(event.eventType.rawValue)"]; if let summary = event.summary, !summary.isEmpty { notesParts.append(summary) }; ekEvent.notes = notesParts.joined(separator: "
"); ekEvent.calendar = eventStore.defaultCalendarForNewEvents; if event.shouldRemind { let alarm: EKAlarm; if let offset = event.reminderOffset { alarm = EKAlarm(relativeOffset: -offset) } else if event.isAllDay { alarm = EKAlarm(relativeOffset: -3 * 3600) } else { alarm = EKAlarm(relativeOffset: -15 * 60) }; ekEvent.addAlarm(alarm) }; do { try eventStore.save(ekEvent, span: .thisEvent); event.systemCalendarEventIdentifier = ekEvent.eventIdentifier; print("[CalendarSyncManager] 已同步到系统日历: \(event.title)") } catch { print("[CalendarSyncManager] 同步系统日历失败: \(error.localizedDescription)") } }
    func removeFromSystemCalendar(event: Event) { guard let ekEventID = event.systemCalendarEventIdentifier else { return }; removeEKEvent(by: ekEventID); event.systemCalendarEventIdentifier = nil; print("[CalendarSyncManager] 已从系统日历移除: \(event.title)") }
    private func removeEKEvent(by identifier: String) { guard let ekEvent = eventStore.event(withIdentifier: identifier) else { return }; do { try eventStore.remove(ekEvent, span: .thisEvent); print("[CalendarSyncManager] 已删除系统日历事件: \(identifier)") } catch { print("[CalendarSyncManager] 删除系统日历事件失败: \(error.localizedDescription)") } }
}